<section class="page-hero shell section-space-small"><p class="eyebrow">COMANDA TA</p><h1>Coșul tău</h1><p>Verifică fiecare alegere înainte de checkout.</p></section>
<section class="cart-page shell section-space-small <?= !$totals['items'] ? 'cart-page-empty' : '' ?>"><?php if(!$totals['items']): ?><div class="empty-state"><h2>Coșul este gol</h2><p>Descoperă piesele pregătite pentru începuturi prețioase.</p><a class="button" href="<?= e(url('/shop')) ?>">Începe cumpărăturile</a></div><?php else: ?><div class="cart-items"><?php foreach($totals['items'] as $item): $custom=json_decode((string)($item['customization_json']??''),true)?:[]; ?><article class="cart-row" data-cart-item="<?= (int)$item['id'] ?>"><img src="<?= e(url($item['image_path'])) ?>" alt="" width="100" height="120"><div><a href="<?= e(url('/produs/'.$item['slug'])) ?>"><h2><?= e($item['name']) ?></h2></a><p><?= e($item['variant_label']?:'Standard') ?></p><?php if(($custom['type']??'')==='gift_box'): ?><p class="gift-cart-note"><?= ($custom['role']??'')==='component'?'Componentă pentru':'Cutie' ?> <?= e($custom['template_name']??'Gift Box') ?><?= !empty($custom['group'])?' · '.e($custom['group']):'' ?></p><?php if(($custom['role']??'')==='box'&&!empty($custom['gift_message'])): ?><p class="gift-cart-message">„<?= e($custom['gift_message']) ?>”</p><?php endif; ?><?php endif; ?><button type="button" data-cart-remove="<?= (int)$item['id'] ?>">Elimină</button></div><label>Cantitate<input type="number" min="1" max="<?= (int)$item['stock_qty'] ?>" value="<?= (int)$item['quantity'] ?>" data-cart-quantity="<?= (int)$item['id'] ?>"></label><strong><?= money((int)$item['price_minor']*(int)$item['quantity']) ?></strong></article><?php endforeach; ?></div><aside class="order-summary"><h2>Sumar comandă</h2><div><span>Subtotal</span><strong><?= money($totals['subtotal_minor']) ?></strong></div><div><span>Reducere</span><strong>-<?= money($totals['discount_minor']) ?></strong></div><div><span>Livrare</span><strong><?= $totals['shipping_minor']?money($totals['shipping_minor']):'Gratuit' ?></strong></div><div class="summary-total"><span>Total</span><strong><?= money($totals['grand_total_minor']) ?></strong></div><form data-coupon-form><?= csrf_field() ?><label>Cod promoțional<input type="text" name="code" value="<?= e($totals['coupon']['code']??'') ?>"></label><button class="button button-outline" type="submit">Aplică</button></form><a class="button" href="<?= e(url('/checkout')) ?>">Continuă spre checkout</a></aside><?php endif; ?></section>